let text = $json.output || "";
text = text.replace(/\\`\\`\\`json/g, "").replace(/\\`\\`\\`/g, "").trim();
try {
  return JSON.parse(text);
} catch (e) {
  const match = text.match(/\\{.*\\}/s);
  if (match) return JSON.parse(match[0]);
  return { suggested_title: "Error", suggested_description: text };
}

